
"use client"

import { useState, useEffect, useMemo, useRef } from "react";
import dynamic from "next/dynamic";
import { useRouter } from "next/navigation";
import { BottomNav } from "@/components/layout/bottom-nav";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Dialog, DialogContent, DialogTitle, DialogDescription, DialogHeader } from "@/components/ui/dialog";
import {
  Zap, Loader2, Navigation, Timer, Flag, Trophy, MapPin, Clock, Gauge, Radio, StopCircle, ShieldAlert, ChevronRight, Map as MapIcon
} from "lucide-react";
import { cn } from "@/lib/utils";
import { useToast } from "@/hooks/use-toast";
import { useUser, useDoc, useFirestore, useMemoFirebase, addDocumentNonBlocking } from "@/firebase";
import { doc, collection, query, where, getCountFromServer } from "firebase/firestore";
import { useDriving } from "@/context/driving-context";
import { ManeuverIcon } from "@/components/navigation/maneuver-icon";

const RouteMap = dynamic(() => import("@/components/telemetry/route-map"), { 
  ssr: false,
  loading: () => <div className="w-full h-full bg-zinc-900 animate-pulse rounded-2xl" />
});

export default function DashboardPage() {
  const router = useRouter();
  const { user, isUserLoading } = useUser();
  const db = useFirestore();
  const {
    speed, isDriving, peakSpeed, tripTime, tripDistance,
    runMode, dragTime, isDragFinished, isDragActive, countdown, isJumpStart,
    isNavigating, currentStep, currentRoadName, distanceToNextStep, remainingDistance, remainingDuration,
    destination, routePoints, currentCoords, heading,
    startTrip, stopTrip, resetTrip, requestWakeLock
  } = useDriving();

  const [mounted, setMounted] = useState(false);
  const [showSummary, setShowSummary] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [cityRank, setCityRank] = useState<number | null>(null);
  const [isRankingLoading, setIsRankingLoading] = useState(false);
  const [liveDragTimer, setLiveDragTimer] = useState(0);
  
  const requestRef = useRef<number>(undefined);
  const startTimeRef = useRef<number>(undefined);

  const { toast } = useToast();

  const profileRef = useMemoFirebase(() => {
    if (!user?.uid || isUserLoading || !db) return null;
    return doc(db, "users", user.uid);
  }, [user?.uid, isUserLoading, db]);
  const { data: profile } = useDoc(profileRef);

  useEffect(() => {
    setMounted(true);
  }, []);

  // Live timer for drag races
  useEffect(() => {
    const animate = () => {
      if (startTimeRef.current) {
        setLiveDragTimer((performance.now() - startTimeRef.current) / 1000);
      }
      requestRef.current = requestAnimationFrame(animate);
    };

    if (isDragActive) {
      startTimeRef.current = performance.now();
      requestRef.current = requestAnimationFrame(animate);
    } else {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
      startTimeRef.current = undefined;
      setLiveDragTimer(0);
    }
    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [isDragActive]);

  const isWaitingForStart = isDriving && !isDragActive && !isDragFinished && 
    (runMode !== 'free') && !isJumpStart;

  const calculateRanks = async () => {
    if (!db || !profile) return;
    setIsRankingLoading(true);
    try {
      const publicRunsCol = collection(db, "public_runs");
      const runTypeLabel = runMode === 'free' ? 'Top Speed' : runMode;
      const val = (runMode === 'free' || !dragTime) ? peakSpeed : dragTime;

      if (!val || val <= 0) {
        setIsRankingLoading(false);
        return;
      }

      if (profile.city) {
        const cityQuery = query(
          publicRunsCol, 
          where("city", "==", profile.city), 
          where("runType", "==", runTypeLabel), 
          runMode === 'free' ? where("peakSpeedKmH", ">", val) : where("dragTime", "<", val)
        );
        const citySnapshot = await getCountFromServer(cityQuery);
        setCityRank(citySnapshot.data().count + 1);
      }
    } catch (e) {
      console.error(e);
    } finally {
      setIsRankingLoading(false);
    }
  };

  useEffect(() => {
    if (isDragFinished && mounted && !showSummary) {
      setShowSummary(true);
      calculateRanks();
      setTimeout(() => stopTrip(), 500);
    }
  }, [isDragFinished, mounted]);

  const handleStartMission = () => {
    if (runMode !== 'free' && speed > 2) {
      toast({ variant: "destructive", title: "GABIM", description: "Ndalo makinën për të filluar testin." });
      return;
    }
    startTrip();
    requestWakeLock();
  };

  const handleStopMission = () => {
    if (isDragFinished || runMode === 'free') {
      setShowSummary(true);
      calculateRanks();
    } else {
      resetTrip();
    }
    stopTrip();
  };

  const handleQuickReport = () => {
    if (!db || !currentCoords || !user?.uid) {
      toast({ variant: "destructive", title: "GABIM GPS", description: "Lokacioni nuk është përcaktuar." });
      return;
    }
    const reportsCol = collection(db, "radar_reports");
    addDocumentNonBlocking(reportsCol, {
      type: 'Radar',
      lat: currentCoords.lat,
      lng: currentCoords.lng,
      location: "Raport i Shpejtë",
      city: profile?.city || "Kosovë",
      createdAt: new Date().toISOString(),
      userId: user?.uid
    });
    toast({ title: "U RAPORTUA!", description: "Radari u shënua në hartë." });
  };

  const handleSaveRun = () => {
    if (!user?.uid || !db || !profile) return;
    setIsSaving(true);
    const runData = {
      userId: user.uid,
      username: profile.username,
      carBrand: profile.carBrand,
      carModel: profile.carModel,
      profileIcon: profile.profileIcon,
      city: profile.city || "Kosovë",
      runType: runMode === 'free' ? 'Top Speed' : runMode,
      durationSeconds: tripTime,
      peakSpeedKmH: peakSpeed,
      distanceMeters: tripDistance,
      dragTime: dragTime,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
      carProfileId: "primary"
    };

    addDocumentNonBlocking(collection(db, "users", user.uid, "runs"), runData);
    addDocumentNonBlocking(collection(db, "public_runs"), runData);

    toast({ title: "Ruajtur!", description: "Gara u sinkronizua në Ranking." });
    setIsSaving(false);
    setShowSummary(false);
    resetTrip();
  };

  if (!mounted || isUserLoading) return <div className="min-h-screen bg-black flex items-center justify-center"><Loader2 className="w-8 h-8 animate-spin text-red-500" /></div>;

  return (
    <div className="flex flex-col min-h-screen bg-[#050505] text-white pb-24 overflow-x-hidden safe-top relative no-scrollbar">
      {/* Navigation Instruction Header */}
      {isNavigating && (
        <div className="px-6 pt-4 z-50 animate-in slide-in-from-top duration-500">
          <Card className="bg-[#1c2a3d]/90 backdrop-blur-2xl p-4 rounded-[1.8rem] border-white/10 shadow-2xl flex items-center gap-4">
             <div className="w-10 h-10 bg-blue-500/20 rounded-xl flex items-center justify-center shrink-0 border border-blue-500/20">
               <ManeuverIcon type={currentStep?.type} modifier={currentStep?.modifier} className="w-6 h-6 text-blue-400" />
             </div>
             <div className="flex-1 min-w-0">
               <h2 className="text-sm font-black text-white leading-tight uppercase truncate">{currentStep?.instruction || "Vazhdoni drejt"}</h2>
               <p className="text-[8px] font-black text-white/40 uppercase tracking-widest mt-0.5">
                 {distanceToNextStep >= 1000 ? `${(distanceToNextStep / 1000).toFixed(1)} km` : `${distanceToNextStep} m`} • {currentRoadName}
               </p>
             </div>
          </Card>
        </div>
      )}

      {/* Header Info */}
      <div className="p-6 flex items-center justify-between z-30 apple-slide-up">
        <div className="flex flex-col">
           <h1 className="text-xl font-black italic tracking-tighter">DRIVERANK <span className="text-red-600">KS</span></h1>
           <span className="text-[8px] font-black uppercase tracking-widest text-muted-foreground">Live Telemetry</span>
        </div>
        <div className="flex items-center gap-3 bg-white/5 px-4 py-2 rounded-2xl border border-white/10">
           <Clock className="w-3.5 h-3.5 text-accent" />
           <span className="text-xs font-black tabular-nums">{new Date().toLocaleTimeString('sq-AL', { hour: '2-digit', minute: '2-digit' })}</span>
        </div>
      </div>

      {/* Main Display Area */}
      <div className="flex-1 flex flex-col items-center justify-center px-4 relative">
        
        {/* Floating Quick Report Button */}
        <div className="absolute right-6 top-0 z-40">
           <Button onClick={handleQuickReport} size="icon" className="w-12 h-12 rounded-2xl bg-red-600/20 border border-red-500/30 text-red-500 shadow-2xl transition-all active:scale-90 hover:bg-red-600/30">
             <Radio className="w-6 h-6 animate-pulse" />
           </Button>
        </div>

        {/* Cockpit Gauge Section */}
        <div className="relative w-full max-w-[340px] aspect-square flex flex-col items-center justify-center apple-scale-in">
          {/* Dynamic Ring Background */}
          <div className="absolute inset-0 rounded-full border-[10px] border-white/5" />
          <div 
            className="absolute inset-[-10px] rounded-full border-[10px] border-red-600/40 transition-all duration-300"
            style={{ 
              clipPath: `inset(0 0 0 0 round 100%)`,
              maskImage: `conic-gradient(black ${Math.min((speed/280)*100, 100)}%, transparent 0)`
            }}
          />

          {/* Mode Specific Visuals */}
          <div className="z-10 flex flex-col items-center w-full h-full justify-center">
            
            {isNavigating ? (
              /* Navigation Mini-Map Cockpit */
              <div className="w-full h-full p-8 relative flex flex-col items-center justify-center">
                 <div className="absolute inset-0 rounded-full overflow-hidden opacity-40">
                    <RouteMap points={routePoints} userLocation={currentCoords} heading={heading} />
                 </div>
                 <div className="relative z-20 flex flex-col items-center bg-black/40 backdrop-blur-md px-6 py-4 rounded-3xl border border-white/10">
                   <span className="text-7xl font-black italic tracking-tighter tabular-nums">{speed}</span>
                   <span className="text-[9px] font-black uppercase tracking-widest text-white/50">KM/H</span>
                 </div>
              </div>
            ) : (
              /* Racing / Drag Cockpit */
              <>
                {isJumpStart ? (
                  <Badge variant="destructive" className="mb-4 font-black uppercase tracking-widest animate-pulse px-4 py-1 text-[10px]">JUMP START!</Badge>
                ) : runMode !== 'free' && (
                  <Badge className="mb-4 bg-accent text-background font-black uppercase tracking-widest text-[10px] italic">{runMode}</Badge>
                )}
                
                <span className={cn(
                  "text-9xl font-black italic tracking-tighter tabular-nums transition-all duration-75",
                  isJumpStart ? "text-red-500" : "text-white"
                )}>
                  {speed}
                </span>
                <span className="text-xs font-black uppercase tracking-[0.4em] text-white/30 mt-2">KM/H</span>
                
                {isDragActive && (
                  <div className="mt-4 flex flex-col items-center bg-accent/10 px-6 py-2 rounded-2xl border border-accent/20">
                     <span className="text-2xl font-black italic text-accent tabular-nums">
                       {liveDragTimer.toFixed(2)}s
                     </span>
                     <span className="text-[8px] font-black uppercase tracking-widest text-accent/50">LIVE DRAG TIMER</span>
                  </div>
                )}
              </>
            )}
          </div>

          {/* F1 Style Countdown System */}
          {isWaitingForStart && (
            <div className="absolute bottom-[-40px] flex items-center gap-3 apple-slide-up">
              {[1, 2, 3, 4, 5].map((i) => (
                <div key={i} className={cn(
                  "w-6 h-6 rounded-full border border-white/10 transition-all duration-300 shadow-2xl",
                  countdown >= i ? "bg-red-600 shadow-[0_0_20px_rgba(220,38,38,0.8)] scale-110" : "bg-zinc-900"
                )} />
              ))}
              <div className={cn(
                "w-8 h-8 rounded-full border border-white/20 transition-all duration-500",
                countdown >= 6 ? "bg-green-500 shadow-[0_0_30px_rgba(34,197,94,1)] scale-125" : "bg-zinc-900"
              )} />
            </div>
          )}
        </div>

        {/* Status Indicators (P-R-N-D) */}
        <div className="flex gap-4 mt-12 apple-slide-up stagger-1">
           {['P', 'R', 'N', 'D'].map(gear => (
             <span key={gear} className={cn(
               "text-xl font-black italic transition-all duration-300",
               (speed === 0 && gear === 'P') || (speed > 0 && gear === 'D') ? "text-red-600 scale-125 drop-shadow-[0_0_10px_rgba(220,38,38,0.5)]" : "text-white/10"
             )}>
               {gear}
             </span>
           ))}
        </div>

        {/* Navigation Stats Row */}
        {isNavigating && (
          <div className="w-full max-w-[340px] grid grid-cols-3 gap-3 mt-6 apple-slide-up stagger-2">
             <div className="flex flex-col items-center">
                <span className="text-[7px] font-black text-white/40 uppercase tracking-widest">ARRITJA</span>
                <span className="text-sm font-black italic text-white">
                  {new Date(Date.now() + remainingDuration * 1000).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                </span>
             </div>
             <div className="flex flex-col items-center border-x border-white/10">
                <span className="text-[7px] font-black text-white/40 uppercase tracking-widest">KOHA</span>
                <span className="text-sm font-black italic text-accent">{Math.round(remainingDuration / 60)} min</span>
             </div>
             <div className="flex flex-col items-center">
                <span className="text-[7px] font-black text-white/40 uppercase tracking-widest">DISTANCA</span>
                <span className="text-sm font-black italic text-white">{(remainingDistance / 1000).toFixed(1)} km</span>
             </div>
          </div>
        )}

        {/* Telemetry Stats Grid */}
        <div className="w-full max-w-[340px] grid grid-cols-2 gap-3 mt-8 stagger-3 apple-slide-up">
           <Card className="glass border-white/5 p-5 rounded-[1.8rem] flex flex-col items-center">
              <Timer className="w-4 h-4 text-accent mb-2" />
              <span className="text-[8px] font-black uppercase tracking-widest text-muted-foreground">KOHA TRIP</span>
              <span className="text-lg font-black italic tabular-nums">{tripTime.toFixed(1)}s</span>
           </Card>
           <Card className="glass border-white/5 p-5 rounded-[1.8rem] flex flex-col items-center">
              <Flag className="w-4 h-4 text-red-500 mb-2" />
              <span className="text-[8px] font-black uppercase tracking-widest text-muted-foreground">DISTANCA</span>
              <span className="text-lg font-black italic tabular-nums">{tripDistance.toFixed(1)}m</span>
           </Card>
        </div>

        {/* Mission Button */}
        <div className="w-full max-w-[340px] mt-8 stagger-4 apple-slide-up">
           <Button
             onClick={isDriving ? handleStopMission : handleStartMission}
             className={cn(
               "w-full h-16 rounded-full font-black text-sm uppercase tracking-widest shadow-2xl transition-all active:scale-95 border-b-4",
               isDriving ? "bg-red-950/40 border-red-500/30 text-white" : "bg-accent border-accent/50 text-background"
             )}
           >
             {isDriving ? "STOP MISSION" : `START ${runMode.toUpperCase()}`}
           </Button>
        </div>
      </div>

      {/* Result Dialog - Fixed Accessibility */}
      <Dialog open={showSummary} onOpenChange={setShowSummary}>
        <DialogContent className="bg-[#0c0c0e] border-white/5 w-[94%] max-w-sm rounded-[2.5rem] p-8 apple-scale-in">
          <DialogHeader>
            <DialogTitle className="text-2xl font-black italic tracking-tighter text-center uppercase">REZULTATI FINALE</DialogTitle>
            <DialogDescription className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest mt-1 text-center">
              {runMode === 'free' ? 'TOP SPEED SESSION' : `${runMode} PERFORMANCE TEST`}
            </DialogDescription>
          </DialogHeader>

          <div className="space-y-6 mt-4">
            <div className="bg-zinc-900/50 p-8 rounded-[2rem] border border-white/5 text-center relative overflow-hidden">
              <div className="absolute inset-0 bg-accent/5 blur-3xl" />
              <span className="text-6xl font-black text-white italic relative z-10 tabular-nums">
                {(runMode === 'free' || !dragTime) ? peakSpeed : dragTime?.toFixed(2)}
              </span>
              <span className="text-xl font-black text-white/50 ml-2 italic relative z-10">
                {(runMode === 'free' || !dragTime) ? 'km/h' : 's'}
              </span>
              
              {isRankingLoading ? (
                <div className="mt-4 flex justify-center"><Loader2 className="w-4 h-4 animate-spin text-accent" /></div>
              ) : (
                <div className="mt-4 flex items-center justify-center gap-2 text-[10px] font-black text-accent uppercase tracking-wider">
                  <Trophy className="w-3 h-3" />
                  {cityRank ? `#${cityRank} NË ${profile?.city?.toUpperCase()}` : "REKORD I RI I KONFIRMUAR!"}
                </div>
              )}
            </div>

            {/* Run Map Recap */}
            <div className="h-40 w-full rounded-2xl overflow-hidden border border-white/5 relative">
               <RouteMap points={routePoints} />
            </div>

            <div className="flex flex-col gap-2">
              <Button onClick={handleSaveRun} disabled={isSaving} className="w-full h-14 bg-red-600 text-white rounded-[1.5rem] font-black uppercase text-[11px] tracking-widest shadow-xl">
                {isSaving ? <Loader2 className="w-4 h-4 animate-spin" /> : "RUAJ NË RANKING"}
              </Button>
              <Button variant="ghost" className="w-full h-10 rounded-xl font-black uppercase text-[9px] text-zinc-600" onClick={() => { setShowSummary(false); resetTrip(); }}>
                ANULO
              </Button>
            </div>
          </div>
        </DialogContent>
      </Dialog>

      <BottomNav />
    </div>
  );
}
